                            + "<tr>" + "<td><b>Longitude:  </b>" + data.handholeData[0][1] + "</td></tr>"
                            + "<tr>" + "<td><b>Latitude:  </b>" + data.handholeData[0][2] + "</td></tr>"
                            + "<tr>" + "<td><b>City:  </b>" + data.handholeData[0][3] + "</td></tr>"
