    function makeSVGJct(tag, attrs, val) { //used in View Junction Mapping
        var el = document.createElementNS('http://www.w3.org/2000/svg', tag);
        for (var k in attrs)
            el.setAttribute(k, attrs[k]);
        $(el).val(val);
        return el;
    }
