                                        $("#" + manholeId).children('.folder').find('> svg').removeClass('fa-folder').addClass('fa-folder-open');
                                        $("#" + manholeId + "_f").children('.folder').find('> svg').removeClass('fa-folder').addClass('fa-folder-open');

