                                        str = "<ul><li id='" + manholeId + "_f' style='display:none;'> <input type='checkbox' class='ManholeJct checkFilter' unchecked name='filter'></input> <span  class='folder' ><i class='fa fa-folder-open' style='color: #08526D'></i></span><span class='TreeSpan' style='color:black;width:236px'>Junctions </span></li></ul></li></ul>";
                                        $("#" + manholeId).append(str);
                                        $("#" + manholeId + " > span").unbind();
                                        $("#" + manholeId + "_f > span").unbind();

                                        str = "<ul><li id='" + data.JunctionID + "' class='JUNCTION_M' style='display:none;width:100px;'><input type='checkbox' class='JctManholes checkFilter' class='filter'></input> <span  class='TreeSpan' style='color:black;width:195px'><img src='" + getContext() + "/resources/NetworkImages/junction.png'> " + junctionName + "  </span></li></ul>";
                                        $("#" + manholeId + "_f").append(str);

                                        $("#" + manholeId + "> span>img").attr('src', getContext() + "/resources/NetworkImages/manholeRed.png");

                                        HandManJuncFormat("Manhole", IdNodeSelectedTemp, manholeId);
