    $("#saveManhole").click(function() {

        if (isNaN(document.getElementById("ManholeLong").value) == true) {
            alert("Incorrect Format of longitude.");
            return false;
        }
        else if (isNaN(document.getElementById("ManholeLat").value) == true) {
            alert("Incorrect Format of latitude.");
            return false;
        }
        else if (document.getElementById("ManholeCity").value == "") {
            alert("City cannot be empty. ");
            return false;
        }
        else if (document.getElementById("ManholeLong").value != "" && document.getElementById("ManholeLat").value != "") {

            var ManholeId = "";
            ManholeName = document.getElementById("ManholeName").value;
            ManholeLong = document.getElementById("ManholeLong").value;
            ManholeLat = document.getElementById("ManholeLat").value;
            ManholeModel = document.getElementById("ManholeModel").value;
            ManholeCity = document.getElementById("ManholeCity").value;
            manholeCreatedDate = document.getElementById("manholeCreateDate").value;
            manholeowner = document.getElementById("manholeOwner").value;
            manholeInstaller = document.getElementById("manholeInstaller").value;
            manholeEngineerName = document.getElementById("manholeEngineerName").value;


            if ($("#projectIdManhole").is(":visible") && $("#projectNameManhole").is(":visible")) {
                if ($("#ManholeProjectId").val() == "") {
                    IdNodeSelectedTemp = "CurrentPhysicalLayer";
                }
                else {
                    IdNodeSelectedTemp = $("#ManholeProjectId").val();
                }
            }


            if (actionManholeContext == "Update") {
                ManholeId = document.getElementById("ManholeId").value;
            }


            $.ajax({
                type: "GET",
                contentType: "application/json; charset=utf-8",
                url: getContext() + '/saveManhole',
                data: {

                    "ManholeId": ManholeId,
                    "ManholeName": ManholeName,
                    "ManholeLong": ManholeLong,
                    "ManholeLat": ManholeLat,
                    "ManholeModel": ManholeModel,
                    "ManholeCity": ManholeCity,
                    "actionManholeContext": actionManholeContext,
                    "ProjectId": IdNodeSelectedTemp,
                    "manholeowner": manholeowner,
                    "manholeCreatedDate": manholeCreatedDate,
                    "manholeInstaller": manholeInstaller,
                    "manholeEngineerName": manholeEngineerName,
                    "updateModfUser": updateModfUser
                },
                dataType: "json",
                success: function(data) {
                    if (data != null) {
                        if (actionManholeContext == "Insert") {
                            checkedJunction = "noJunction";

                            str = "<ul><li id='" + data.ManholeId + "' class='MANHOLE' style='width:100px;'> <input type='checkbox' class='Manhole checkFilter' checked  class='filter'  name='Element'></input> <span class='TreeSpan' style='color:black;'><img src='" + getContext() + "/resources/NetworkImages/manholeRed.png'> " + data.ManholeName + " </span></li></ul>";
                            $("#Manhole_f_" + IdNodeSelectedTemp + "").append(str);

                            HandManJuncFormat("Manhole", IdNodeSelectedTemp, data.ManholeId);

                        }
                        //update manhole
                        else {
                            checkManholeFilter = data.countJct.length;

                            $("#" + data.ManholeId + "_f >span").unbind("click");
                            $("#" + data.ManholeId).children(':checkbox').prop("checked", true);

                            // No junction to append
                            if (data.countJct.length == 0) {
                                checkedJunction = "noJunction";
                                $("#" + data.ManholeId + "> .TreeSpan").html("<img style='color: #08526D;' src='" + getContext() + "/resources/NetworkImages/manholeRed.png'>" + " " + data.ManholeName + " ");
                                $("#" + data.ManholeId + "> .folder").html("");
                                $("#" + data.ManholeId + "_f").children('ul').remove();
                                $("#" + data.ManholeId + "_f").remove();

                            }
                            //Junctions exists (Append)
                            else {
                                checkedJunction = "Junction";

                                $("#" + data.ManholeId + "> .folder").remove();
                                $("<span class='folder' > <i class='fa fa-folder' style='color: #08526D'></i></span>").insertBefore("#" + data.ManholeId + "> .TreeSpan");

                                $("#" + data.ManholeId + "> ul").remove();
                                $("#" + data.ManholeId + "> .TreeSpan").html("<img src='" + getContext() + "/resources/NetworkImages/manholeRed.png'>  " + data.ManholeName + "  ");
                                str = "<ul><li id='" + data.ManholeId + "_f' class='Junction_folder' style='display:none;'> <input type='checkbox' class='ManholeJct checkFilter' checked name='filter'></input> <span  class='folder' ><i class='fa fa-folder' style='color: #08526D'></i></span><span class='TreeSpan' style='color:black;' > Junctions </span></li></ul>";
                                $("#" + data.ManholeId).append(str);

                                $("#" + data.ManholeId + " > span").unbind();
                                $("#" + data.ManholeId + "_f > span").unbind();

                                $("#network_tree i").css('margin-right', '5px');

                                var jctID = "";
                                if (data.countJct) {
                                    for (i = 0;i < data.countJct.length;i++) {
                                        jctID = data.countJct[i][0];
                                        window["" + jctID] = [];
                                        window["" + jctID] = data.countJct[i];

                                        //Append junctions to manhole
                                        str = "<ul><li id='" + data.countJct[i][0] + "' class='JUNCTION_M' style='display:none;width:100px;'><input type='checkbox' class='JctManholes checkFilter' checked name='filter'></input> <span class='TreeSpan' style='color:black;'><img src='" + getContext() + "/resources/NetworkImages/junction.png'>  " + data.countJct[i][1] + " </span></li></ul>";
                                        $("#" + data.ManholeId + "_f").append(str);

                                        CreateJunctionClickEvent(jctID, "Manhole");

                                        $("#" + jctID + " > span").bind("contextmenu", function() {
                                            selectedManIdContext = $(this).parents().eq(4).attr('id');
                                            selectedManholeJct = $(this).parent().attr('id');
                                            openContext(selectedManIdContext, "", singleJunction, event)
                                        });

                                    }	//end loop 
                                }
                                junctionCheckFilter("Manhole");
                            }//end else junction to append 		

                            EnableOrigination = false;

                        } // end update manhole
                        $("#" + data.ManholeId + " > .TreeSpan").css("display", "inline");
                        $("#manholeModal").modal('hide');

                        // bind context menu event to Manhole 
                        $("#" + data.ManholeId + " > .TreeSpan").bind("contextmenu", function() {
                            selectedManIdContext = $(this).parent().attr('id');
                            IdNodeSelectedTemp = $(this).parents().eq(2).attr('id').split("Manhole_f_")[1];
                            menuName = singleManhole;
                            openContext(selectedManIdContext, "", singleManhole, event)
                        });

                        $("#manholeCheckAllBoq").prop("checked", true);

                        window["" + data.ManholeId] = "";
                        window["" + data.ManholeId] = [data.ManholeId, data.ManholeName, ManholeLong, ManholeLat, IdNodeSelectedTemp, data.countJct, ManholeCity, manholeInstaller, manholeEngineerName];

                        if (typeof infowindow !== 'undefined') {
                            infowindow.close();
                        }
                        if (checkedJunction == "noJunction") {
                            create_Marker_Click(data.ManholeId, data.ManholeName, ManholeLong, ManholeLat, markersManhole, markerClusterManhole, "No_Junction", "");
                            //createManhole_Marker_Click(data.ManholeId,data.ManholeName,ManholeLong,ManholeLat,markersManhole,markerClusterManhole,"No_Junction");
                            markerClusterManhole.addMarker(markersManhole["" + data.ManholeId]);
                            ManholeCheckFilter(data.ManholeId);
                        }
                        else if (checkedJunction == "Junction") {
                            create_Marker_Click(data.ManholeId, data.ManholeName, ManholeLong, ManholeLat, markersManhole, markerClusterManhole, "Junction", "");
                            //createManhole_Marker_Click(data.ManholeId,data.ManholeName,ManholeLong,ManholeLat,markersManhole,markerClusterManhole,"Junction");
                            markerClusterManhole.addMarker(markersManhole["" + data.ManholeId]);
                            ManholeCheckFilter(data.ManholeId);
                        }

                        // remove the selection of previous item if exist and add it to the new one
                        if (IdSelectedTemp != "") {
                            $("#" + IdSelectedTemp + " > .TreeSpan").removeClass("selected-span");
                            $("#" + IdSelectedTemp + " > .TreeSpan").css("background", "");
                        }
                        $("#" + data.ManholeId + " > .TreeSpan").addClass("selected-span");
                        $("#" + data.ManholeId + " > .TreeSpan").css("background-color", "#97b9cc");
                        IdSelectedTemp = data.ManholeId;

                        $("#manholeModal").find("input,textarea,select").val('').end().find("input[type=checkbox], input[type=radio]").prop("checked", "").end();
                        map.setZoom(11);

                        if ($("#manholesMapCheck_Labels").prop("checked") == true) {
                            markersManhole[data.ManholeId].setLabel({ text: ManholeName, className: "marker-position-manhole", color: "red" });
                        }
                        panTo(ManholeLat, ManholeLong);

                    }
                    data = null;
                },
                error: function(result) {
                    alert("Error");
                }
            });

        }
        else {
            alert(" Missing Fields!");
        }

    });

