    function uploadExcelData(fileId, appendToCheckBox, tableID) {

        //Reference the FileUpload element.
        var fileUpload = document.getElementById(fileId);

        if (fileId != "importDBFile") {
            if (document.querySelector("#" + appendToCheckBox).checked === false) {
                $("#" + tableID + " > tbody").empty();
            }
        }


        //Validate whether File is valid Excel file.
        var regex = /^([a-zA-Z0-9\s_\\.\-:])+(.xls|.xlsx)$/;
        if (regex.test(fileUpload.value.toLowerCase())) {
            if (typeof (FileReader) != "undefined") {
                var reader = new FileReader();

                //For Browsers other than IE.
                if (reader.readAsBinaryString) {
                    reader.onload = function(e) {
                        if (tableID == "auxiliaryTable") {
                            GetTableFromExcelSheet(e.target.result, "loaderDiv", "auxiliaryTable", "AuxPt_AppendTo")
                        }
                        else if (tableID == "auxiliaryTableStrands") {
                            GetTableFromExcelSheet(e.target.result, "loaderDivStrand", "auxiliaryTableStrands", "AuxPt_AppendTo_Strand")
                        }
                        else if (tableID == "auxiliary_trenchTable") {
                            GetTableFromExcelSheet(e.target.result, "loaderDivTrench", "auxiliary_trenchTable", "AuxPt_AppendTo_Trench")
                        }
                        else if (tableID == "auxiliary_ductTable") {
                            GetTableFromExcelSheet(e.target.result, "loaderDivDuct", "auxiliary_ductTable", "AuxPt_AppendTo_Duct")
                        }
                        else if (tableID == "TubeAuxTable") {
                            GetTableFromExcelSheet(e.target.result, "loaderDivFiberTube", "TubeAuxTable", "AuxPt_AppendTo_FiberTube")
                        }
                        else if (tableID == "StrandAuxTable") {
                            GetTableFromExcelSheet(e.target.result, "loaderDivFiberStrand", "StrandAuxTable", "AuxPt_AppendTo_FiberStrand")
                        }
                        else if (fileId == "importDBFile") {
                            LoadDBFromExcel(e.target.result)
                        }
                        else {
                            GetTableFromExcelSheet(e.target.result, "loaderDivTube", "auxiliaryTableTubes", "AuxPt_AppendTo_Tube")
                        }
                    };
                    reader.readAsBinaryString(fileUpload.files[0]);
                } else {
                    //For IE Browser.
                    reader.onload = function(e) {
                        var data = "";
                        var bytes = new Uint8Array(e.target.result);
                        for (var i = 0;i < bytes.byteLength;i++) {
                            data += String.fromCharCode(bytes[i]);
                        }
                        if (tableID == "auxiliaryTable") {
                            GetTableFromExcelSheet(data, "loaderDiv", "auxiliaryTable", "AuxPt_AppendTo")
                        }
                        else if (tableID == "auxiliaryTableStrands") {
                            GetTableFromExcelSheet(data, "loaderDivStrand", "auxiliaryTableStrands", "AuxPt_AppendTo_Strand")
                        }
                        else if (tableID == "auxiliary_trenchTable") {
                            GetTableFromExcelSheet(data, "loaderDivTrench", "auxiliary_trenchTable", "AuxPt_AppendTo_Trench")
                        }
                        else if (tableID == "auxiliary_ductTable") {
                            GetTableFromExcelSheet(data, "loaderDivDuct", "auxiliary_ductTable", "AuxPt_AppendTo_Duct")
                        }
                        else if (tableID == "TubeAuxTable") {
                            GetTableFromExcelSheet(data, "loaderDivFiberTube", "TubeAuxTable", "AuxPt_AppendTo_FiberTube")
                        }
                        else if (tableID == "StrandAuxTable") {
                            GetTableFromExcelSheet(data, "loaderDivFiberStrand", "StrandAuxTable", "AuxPt_AppendTo_FiberStrand")
                        }
                        else if (fileId == "importDBFile") {
                            LoadDBFromExcel(data)
                        }
                        else {
                            GetTableFromExcelSheet(data, "loaderDivTube", "auxiliaryTableTubes", "AuxPt_AppendTo_Tube")
                        }
                    };
                    reader.readAsArrayBuffer(fileUpload.files[0]);
                }
            } else {
                alert("This browser does not support HTML5.");
            }
        } else {
            alert("Please upload a valid Excel file.");
        }
    }


    function LoadDBFromExcel(data) {
        //Read the Excel File data in binary
        var data_length = 0;
        var workbook = XLSX.read(data, {
            type: 'binary'
        });

        //get the name of First Sheet.
        var Sheet = workbook.SheetNames[0];

        //Read all rows from First Sheet into an JSON array.
        var excelRows = XLSX.utils.sheet_to_row_object_array(workbook.Sheets[Sheet]);

        console.log("excel row " + excelRows[0])
        //Add the data rows from Excel file.

        let loaded_data = [];
        let dictObj = {};
        let dict = [];

        for (var i = 0;i < excelRows.length;i++) {

            //Add the data row.
            var longitude = excelRows[i].Longitude ? excelRows[i].Longitude : excelRows[i].longitude

            var latitude = excelRows[i].Latitude ? excelRows[i].Latitude : excelRows[i].latitude;

            var siteID = excelRows[i].SiteID;

            var siteName = excelRows[i].SiteName;

            var Nofports = excelRows[i].Nofports;

            var city = excelRows[i].City;

            var name = excelRows[i].Name;

            var NetworkLevel = excelRows[i].NetworkLevel;



            dictObj.longitude = longitude
            dictObj.siteID = siteID
            dictObj.siteName = siteName
            dictObj.Nofports = Nofports
            dictObj.latitude = latitude
            dictObj.city = city
            dictObj.name = name
            dictObj.NetworkLevel = NetworkLevel
            dict.push(dictObj);
            dictObj = {};
        }

        var token = $('input[name="csrfToken"]').attr('value');

        $.ajax({
            type: "POST",
            headers: {
                'X-CSRFToken': token
            },
            url: getContext() + '/saveLoadedDistributionBoard',

            data: {

                "dictParameterLoadedDB": dict,
                "ProjectId": IdNodeSelectedTemp

            },
            dataType: "json",
            success: function(data) {

                if (data != null) {

                    data_length = data.distributionBoardDetails.length;
                    for (var i = 0;i < data.distributionBoardDetails.length;i++) {

                        window["" + data.distributionBoardDetails[i][0]] = [];
                        window["" + data.distributionBoardDetails[i][0]] = [data.distributionBoardDetails[i][0], data.distributionBoardDetails[i][1], data.distributionBoardDetails[i][2], data.distributionBoardDetails[i][3], data.distributionBoardDetails[i][4], data.distributionBoardDetails[i][5], IdNodeSelectedTemp, data.distributionBoardDetails[i][6], data.distributionBoardDetails[i][7]];

                        if (data.distributionBoardDetails[i][7] == "backbone") {
                            str = "<ul><li id='" + data.distributionBoardDetails[i][0] + "'  class='DistributionBoard' style='width:100px;'><input type='checkbox' class='DistBoard checkFilter' checked name='filter'></input> <span class='TreeSpan' style='color:black;width:355px'><img class='image' src='" + getContext() + "/resources/NetworkImages/backboneDB.png'> " + data.distributionBoardDetails[i][3] + "/" + data.distributionBoardDetails[i][0] + " </span></li></ul>";
                        }
                        else if (data.distributionBoardDetails[i][7] == "metro") {
                            str = "<ul><li id='" + data.distributionBoardDetails[i][0] + "'  class='DistributionBoard' style='width:100px;'><input type='checkbox' class='DistBoard checkFilter' checked name='filter'></input> <span class='TreeSpan' style='color:black;width:355px'><img class='image' src='" + getContext() + "/resources/NetworkImages/metroDb.png'> " + data.distributionBoardDetails[i][3] + "/" + data.distributionBoardDetails[i][0] + " </span></li></ul>";
                        }
                        else if (data.distributionBoardDetails[i][7] == "access") {
                            str = "<ul><li id='" + data.distributionBoardDetails[i][0] + "'  class='DistributionBoard' style='width:100px;'><input type='checkbox' class='DistBoard checkFilter' checked name='filter'></input> <span class='TreeSpan' style='color:black;width:355px'><img class='image' src='" + getContext() + "/resources/NetworkImages/accessDb.png'> " + data.distributionBoardDetails[i][3] + "/" + data.distributionBoardDetails[i][0] + " </span></li></ul>";
                        }
                        $("#DistributionBoard_" + data.distributionBoardDetails[i][7] + "__" + IdNodeSelectedTemp).append(str);


                        $("#" + data.distributionBoardDetails[i][0]).contextmenu(function() {
                            menuName = singleDistBoard;
                            selectedDistBoardContext = $(this).attr('id');
                            selectedDistBoardName = $(this).text();
                            openContext(selectedDistBoardContext, selectedDistBoardName, singleDistBoard, event);
                        });

                        if (data.distributionBoardDetails[i][7] == "backbone") {
                            create_Marker_Click(data.distributionBoardDetails[i][0], data.distributionBoardDetails[i][3], data.distributionBoardDetails[i][1], data.distributionBoardDetails[i][2], markersDistBoard, markerClusterBackboneDistBoard, "", data.distributionBoardDetails[i][6]);
                            markerClusterBackboneDistBoard.addMarker(markersDistBoard["" + data.distributionBoardDetails[i][0]]);
                            clusterName = markerClusterBackboneDistBoard;
                        }
                        else if (data.distributionBoardDetails[i][7] == "metro") {
                            create_Marker_Click(data.distributionBoardDetails[i][0], data.distributionBoardDetails[i][3], data.distributionBoardDetails[i][1], data.distributionBoardDetails[i][2], markersDistBoard, markerClusterMetroDistBoard, "", data.distributionBoardDetails[i][6]);
                            markerClusterMetroDistBoard.addMarker(markersDistBoard["" + data.distributionBoardDetails[i][0]]);
                            clusterName = markerClusterMetroDistBoard;
                        }
                        else {
                            create_Marker_Click(data.distributionBoardDetails[i][0], data.distributionBoardDetails[i][3], data.distributionBoardDetails[i][1], data.distributionBoardDetails[i][2], markersDistBoard, markerClusterAccessDistBoard, "", data.distributionBoardDetails[i][6]);
                            markerClusterAccessDistBoard.addMarker(markersDistBoard["" + data.distributionBoardDetails[i][0]]);
                            clusterName = markerClusterAccessDistBoard;
                        }


                        DistributionBoardCheckFilter(data.distributionBoardDetails[i][0], "", clusterName);

                        if ($("#dBMapCheck_Labels").prop("checked") == true) {
                            markersDistBoard[data.distributionBoardDetails[i][0]].setLabel({ text: data.distributionBoardDetails[i][3], className: "marker-position-dB", color: "#5665F9" });
                        }





                        $("#" + data.distributionBoardDetails[i][0] + " > .TreeSpan").css("display", "inline");

                        // remove the selection of previous item if exist and add it to the new one

                        if (IdSelectedTemp != "") {
                            $("#" + IdSelectedTemp + " > .TreeSpan").removeClass("selected-span");
                            $("#" + IdSelectedTemp + " > .TreeSpan").css("background", "");
                        }
                        $("#" + data.distributionBoardDetails[i][0] + " > .TreeSpan").addClass("selected-span");
                        $("#" + data.distributionBoardDetails[i][0] + " > .TreeSpan").css("background-color", "#97b9cc");
                        IdSelectedTemp = data.distributionBoardDetails[i][0];

                        var childrenInitial = $("#initial_ul_" + IdNodeSelectedTemp + "").find(' > ul > li');
                        var projectInitial = $("#initial_ul_Projects").find('>ul > #' + IdNodeSelectedTemp);
                        var projectRel = $("#" + IdNodeSelectedTemp + "").find('>ul > #initial_ul_' + IdNodeSelectedTemp);
                        var children = $("#DistributionBoard_f_" + IdNodeSelectedTemp + "").find(' > ul > li');

                        if (!children.is(":visible")) {
                            $("#DistributionBoard_f_" + IdNodeSelectedTemp + "").children('.folder').find('> svg').removeClass('fa-folder').addClass('fa-folder-open');
                            $("#initial_ul_" + IdNodeSelectedTemp + "").children('.folder').find('> svg').removeClass('fa-folder').addClass('fa-folder-open');

                        }
                        children.show('fast');
                        childrenInitial.show('fast');
                        projectInitial.show('fast');
                        projectRel.show('fast');

                    }

                }
                $('#LoaderConfirmationModal').find('input:text').val('');
                $("#LoaderConfirmationHeader").text("Created Distribution Board: ");
                $("#LoaderConfirmationbody").text("Number of Created Distribution Boards are: " + data_length);
                if (data.IgnoredDB.length > 0) {
                    $("#IgnoredDBBody").text("The Following Rows Number in the Excel Sheet are Ignored: " + data.IgnoredDB);
                }
                $("#LoaderConfirmationModal").modal('show');
            },
            error: function(result) {
                alert("Error");
            }
        });



        $("#distributionBoardLoaderModal").modal('hide');


    }

    function GetTableFromExcelSheet(data, loaderDivId, tableID, appendToCheckBox) {
        //Read the Excel File data in binary
        var workbook = XLSX.read(data, {
            type: 'binary'
        });

        //get the name of First Sheet.
        var Sheet = workbook.SheetNames[0];

        //Read all rows from First Sheet into an JSON array.
        var excelRows = XLSX.utils.sheet_to_row_object_array(workbook.Sheets[Sheet]);


        //Add the data rows from Excel file.

        let dict = [];
        let dictObj = {};

        for (var i = 0;i < excelRows.length;i++) {

            //Add the data row.
            var longitude = excelRows[i].Longitude ? excelRows[i].Longitude : excelRows[i].longitude

            var latitude = excelRows[i].Latitude ? excelRows[i].Latitude : excelRows[i].latitude;

            var auxName = excelRows[i].Description;

            dictObj.longitude = longitude
            dictObj.auxName = auxName
            dictObj.latitude = latitude

            dict.push(dictObj);
            dictObj = {};
        }
        var token = $('input[name="csrfToken"]').attr('value');

        //console.log(dict)

        if (dict.length > 1500) {
            alert("The number of entered auxiliaries can not exceed 1500 ");
            return false;
        }
        $.ajax({
            type: "POST",
            url: getContext() + '/SearchForAuxName',
            headers: {
                'X-CSRFToken': token
            },
            data: {
                "dictParameter": dict,
            },
            beforeSend: function() {
                $("#upload").prop("disabled", true);
                $("#" + loaderDivId).show();
            },
            dataType: "json",
            success: function(data) {
                $("#" + loaderDivId).hide();
                if (data != null) {

                    var countAuxRowBoq = $("#" + tableID + " > tbody").children().length;
                    if (document.querySelector("#" + appendToCheckBox).checked) {
						console.log("It is appending");
                        if (tableID == "auxiliary_trenchTable") {
                            indextrench = countAuxRowBoq;
                        }
                        else if (tableID == "auxiliary_ductTable") {
                            indexduct = countAuxRowBoq;
                        }
                        else if (tableID == "TubeAuxTable") {
                            indexTubeAux = countAuxRowBoq;
                        }
                        else if (tableID == "StrandAuxTable") {
                            indexStrandAux = countAuxRowBoq;
                        }
                        else {
                            index = countAuxRowBoq;
                        }
                    }
                    else {
						const tbody = $("#" + tableID + " > tbody")[0];
						tbody.innerHTML = "";
						
                        if (tableID == "auxiliary_trenchTable") {
                            indextrench = 0;
                        }
                        else if (tableID == "auxiliary_ductTable") {
                            indexduct = 0;
                        }
                        else if (tableID == "TubeAuxTable") {
                            indexTubeAux = 0;
                        }
                        else if (tableID == "StrandAuxTable") {
                            indexStrandAux = 0;
                        }
                        else {
                            index = 0;
                        }
                    }

                    if (tableID == "auxiliaryTable") {
						// As the controller is returning List<List<Object>>, so we will use directly data and not data.auxWithName which we were using it when the type of the returned data is Map. 
                        fiberAction = "Import";
                        TargetFiber.Action = fiberAction;
						console.log("the returned data is: ", data);
                        AuxAppendBOQ(data, "", "", TargetFiber, index);
                        TargetFiber.Action = "";
                    }
                    else if (tableID == "auxiliaryTableStrands") {
                        strandAction = "Import";
                        TargetStrand.Action = strandAction;
                        AuxAppendBOQ(data, "", "", TargetStrand, index);
                        TargetStrand.Action = "";
                    }
                    else if (tableID == "auxiliary_trenchTable") {
                        trenchAction = "Import";
                        TargetTrench.Action = trenchAction;
                        AuxAppendBOQ(data, "", "", TargetTrench, indextrench);
                        TargetTrench.Action = "";
                    }
                    else if (tableID == "auxiliary_ductTable") {
                        ductAction = "Import";
                        TargetDuct.Action = ductAction;
                        AuxAppendBOQ(data, "", "", TargetDuct, indexduct);
                        TargetDuct.Action = "";
                    }
                    else if (tableID == "TubeAuxTable") {
                        fiberTubeAction = "Import";
                        TargetFiberTube.Action = fiberTubeAction;
                        TubeStrandAuxAppendBOQ(data, "", TargetFiberTube, indexTubeAux);
                        TargetFiberTube.Action = "";
                    }
                    else if (tableID == "StrandAuxTable") {
                        fiberStrandAction = "Import";
                        TargetFiberStrand.Action = fiberStrandAction;
                        TubeStrandAuxAppendBOQ(data, "", TargetFiberStrand, indexStrandAux);
                        TargetFiberStrand.Action = "";
                    }
                    else {
                        tubeAction = "Import";
                        TargetTube.Action = tubeAction;
                        AuxAppendBOQ(data, "", "", TargetTube, index);
                        TargetTube.Action = "";
                    }
                    objDiv = document.getElementById("" + tableID);
                    objDiv.scrollTop = objDiv.scrollHeight;
                }
                data = null,
                dict = null
            },
            complete: function() {
                // Enable the button after a delay (example: 4 seconds)
                setTimeout(function() {
                    $("#upload").prop("disabled", false);
                }, 4000);
            },
            error: function(result) {
                alert("Error");
            }
        });
    };



