    $("#selectAll_AuxTube").on('click', function() {
        if ($(this).hasClass('allChecked')) {
            $('input[type="checkbox"]', '#auxiliaryTableTubes').prop('checked', false);
            showHideAllPoints(selectedTube, "tubeCheckSequence", "Hide");

            window['tubeCheckPoints_' + selectedTube] = "unchecked";
            window['tubeCheckRealPoints_' + selectedTube] = "unchecked";
            window['tubeCheckSequence_' + selectedTube] = "unchecked";

            //Remove the unchecked tube points from array 
            var index = allTubesShowPoint.indexOf(selectedTube);
            if (index > -1) {
                allTubesShowPoint.splice(index, 1);
            }

            //Remove the unchecked tube points from array 
            var index = allTubesShowRealPoint.indexOf(selectedTube);
            if (index > -1) {
                allTubesShowRealPoint.splice(index, 1);
            }

            //Remove the unchecked tube points from array 
            var index = allTubesShowSeq.indexOf(selectedTube);
            if (index > -1) {
                allTubesShowSeq.splice(index, 1);
            }

            $("#tubeCheckIconSequence").hide();
            $("#tubeCheckIconBox").hide();
            $("#tubeCheckIconRealPoints").hide();


        }
        else {


            checkLabel = "checked";
            //Used to check if the labels in dropdown are checked 
            allcheckedLabels = [];
            if ($(".checkboxSpan:checked").length > 0) {
                $(".checkboxSpan").each(function() {
                    if ($(this).is(":checked")) {
                        var id = $(this).attr('id');
                        allcheckedLabels.push(id);
                    }
                });
            }

            $('input[type="checkbox"]', '#auxiliaryTableTubes').prop('checked', true);
            showHideAllPoints(selectedTube, "tubeCheckSequence", "Show");
            window['tubeCheckPoints_' + selectedTube] = "checked";
            $("#tubeCheckIconBox").show();

            if (allTubesShowPoint.includes(selectedTube) == false) {
                allTubesShowPoint.push(selectedTube);
            }
        }

        $(this).toggleClass('allChecked');

    });


