    function fireManualOriginationTermination(modalID, checkboxClass, ID, Type, Longitude, Latitude, city, srcDst, orgDest) {

        //Reset the origination / termination 
        if (window["" + orgDest].length > 0) {

            if ($("#" + ID).val().split("_")[0] == "WARE" || $("#" + ID).val().split("_")[0] == "CUST") {
                if (siteCltSrcMarkers[$("#" + ID).val().split(":")[0]]) {
                    siteCltSrcMarkers[$("#" + ID).val().split(":")[0]].setMap(null);
                }
            }
            else if ($("#" + ID).val().split("_")[0] == "MH") {
                var ManId = $("#" + ID).val().split(":")[0];
                markersManhole[ManId].setMap(null);
                $("#" + ManId).children(':checkbox').prop("checked", false);
                markerClusterManhole.removeMarker(markersManhole[ManId]);
                if ($("#Manhole_f_CurrentPhysicalLayer").find(".Manhole:checked").length == 0) {
                    $("#manholeCheckAllBoq").prop("checked", false);
                }
                else {
                    $("#manholeCheckAllBoq").prop("checked", true);
                }

            }
            else if ($("#" + ID).val().split("_")[0] == "HH") {
                var HandId = $("#" + ID).val().split(":")[0];
                markersHandhole[HandId].setMap(null);
                $("#" + HandId).children(':checkbox').prop("checked", false);
                markerClusterHandhole.removeMarker(markersHandhole[HandId]);
                if ($("#Handhole_f_CurrentPhysicalLayer > .AllHandholes").is(":checked")) {
                    $("#handholeCheckAllBoq").prop("checked", false);
                }
                else {
                    $("#handholeCheckAllBoq").prop("checked", true);
                }

            }
            else if ($("#" + ID).val().split("_")[0] == "DB") {
                var distBoardId = $("#" + ID).val().split(":")[0];
                markersDistBoard[distBoardId].setMap(null);
                $("#" + distBoardId).children(':checkbox').prop("checked", false);
                if (window["" + distBoardId][8] == "backbone") {
                    markerClusterBackboneDistBoard.removeMarker(markersDistBoard[distBoardId]);
                }
                else if (window["" + distBoardId][8] == "metro") {
                    markerClusterMetroDistBoard.removeMarker(markersDistBoard[distBoardId]);

                }
                else if (window["" + distBoardId][8] == "access") {
                    markerClusterAccessDistBoard.removeMarker(markersDistBoard[distBoardId]);
                }

                if ($("#DistributionBoard_f_CurrentPhysicalLayer").find(".DistBoard:checked").length == 0) {
                    $("#distBoardCheckAllBoq").prop("checked", false);
                }
                else {
                    $("#distBoardCheckAllBoq").prop("checked", true);
                }
            }
        }
        window["" + orgDest] = [];
        uncheckAutoCompleteCheckboxes("" + checkboxClass);
        $('#' + modalID).find('input:text').val('');
        $('#' + modalID).find('input:checkbox').prop("checked", false);

        $("#" + modalID).modal('show');
        SourceDestinationAutoComplete(checkboxClass, Type, ID, Longitude, Latitude, city, "", "", "", srcDst);
    }


