    function saveOriginationTermination(modalID, ID, Type, City, Longitude, Latitude, orgDest) {

        if ($("#" + ID).val() == "") {
            if (orgDest == "Origination") {
                alert("Source is required!");
            }
            else {
                alert("Destination is required!");
            }
        }
        else {
            if (orgDest == "Origination") {
                window["Origination"] = [$("#" + ID).val(), $("#" + Type).val(), $("#" + City).val(), $("#" + Longitude).val(), $("#" + Latitude).val()];
            }
            else {
                window["Termination"] = [$("#" + ID).val(), $("#" + Type).val(), $("#" + City).val(), $("#" + Longitude).val(), $("#" + Latitude).val()];
            }

            panTo($("#" + Latitude).val(), $("#" + Longitude).val());


            if ($("#" + ID).val().split("_")[0] == "WARE" || $("#" + ID).val().split("_")[0] == "CUST") {
                var wareID = $("#" + ID).val().split(":")[0];
                createSiteCltMarker(wareID, $("#" + ID).val(), $("#" + Latitude).val(), $("#" + Longitude).val(), siteCltSrcMarkers);
            }
            else if ($("#" + ID).val().split("_")[0] == "MH") {
                var ManId = $("#" + ID).val().split(":")[0];
                if (markersManhole[ManId].getMap() == null) {
                    markersManhole[ManId].setMap(map);
                    markerClusterManhole.addMarker(markersManhole[ManId]);
                    $("#" + ManId).children(':checkbox').prop("checked", true);
                    $("#manholeCheckAllBoq").prop("checked", true);
                }
            }
            else if ($("#" + ID).val().split("_")[0] == "HH") {
                var HandId = $("#" + ID).val().split(":")[0];
                if (markersHandhole[HandId].getMap() == null) {
                    markersHandhole[HandId].setMap(map);
                    markerClusterHandhole.addMarker(markersHandhole[HandId]);
                    $("#" + HandId).children(':checkbox').prop("checked", true);
                    $("#handholeCheckAllBoq").prop("checked", true);
                }
            }
            else if ($("#" + ID).val().split("_")[0] == "DB") {
                var Id = $("#" + ID).val().split(":")[0];
                if (markersDistBoard[Id].getMap() == null) {
                    markersDistBoard[Id].setMap(map);
                    if (window["" + Id][8] == "backbone") {
                        markerClusterBackboneDistBoard.addMarker(markersDistBoard[Id]);
                    }
                    else if (window["" + Id][8] == "metro") {
                        markerClusterMetroDistBoard.addMarker(markersDistBoard[Id]);
                    }
                    else if (window["" + Id][8] == "access") {
                        markerClusterAccessDistBoard.addMarker(markersDistBoard[Id]);
                    }
                    $("#" + Id).children(':checkbox').prop("checked", true);
                    $("#distBoardCheckAllBoq").prop("checked", true);
                }
            }
            $("#" + modalID).modal('hide');
        }
    }




