function treeCollapseFolder(selector, type, clss) {
    if (selector == null) {
        selector = " .folder";
    }
    $(document)
        .off('click.treeCollapse', selector)
        .on('click.treeCollapse', selector, function(e) {

            var id = $(this).parent().attr('id');

            if (id == "FiberPath_f_CurrentPhysicalLayer" && flag == 0 && $(this).parent().find(' > ul > li').is(":hidden")) {
                getFiberPath();
            } else if (id == "NodeActive_f_CurrentPhysicalLayer" && nodeFlag == 0 && $(this).parent().find(' > ul > li').is(":hidden")) {
                getNode();
            }

            else if (id == "DistributionBoard_f_CurrentPhysicalLayer" && DBFlag == 0 && $(this).parent().find(' > ul > li').is(":hidden")) {
                getDB("", "");
            }
            //zeina

            else if (id == "Junction_f_CurrentPhysicalLayer" && junctionFlag == 0) {
                getJunction();
            } else if (id == "Site_f_CurrentPhysicalLayer" && siteFlag == 0) {
                getSite("collaps", null);
            } else if (id.startsWith('PROJECT_') && projectflag[id] == 0) {
                getProject(id);
            }
            var children = $(this).parent().find(' > ul > li');

            if (children.length > 0) {
                // Has children: toggle their visibility

                if (children.is(":visible")) {
                    children.hide(type);
                    $(this).parent().children(clss).find('> svg')
                        .addClass('fa-folder')
                        .removeClass('fa-folder-open');
                } else {
                    children.show(type);
                    $(this).parent().children(clss).find('> svg')
                        .addClass('fa-folder-open')
                        .removeClass('fa-folder');
                }
            } else {
                // No children: just toggle the folder icon
                var icon = $(this).parent().children(clss).find('> svg');
                if (icon.hasClass('fa-folder-open')) {
                    icon.removeClass('fa-folder-open').addClass('fa-folder');
                } else {
                    icon.removeClass('fa-folder').addClass('fa-folder-open');
                }
            }
            e.stopPropagation();
        });
}



function tree_Prop(selector) {
    $(selector).bind('click', function(e) {
        var children = $(this).parent('li').find(' > ul > li');
        if (children.is(":visible")) {

            children.hide('fast');
            $(this).parent('li').children('.folder').find('> svg').addClass('fa-folder').removeClass('fa-folder-open');
        }
        else {

            children.show('fast');
            $(this).parent('li').children('.folder').find('> svg').addClass('fa-folder-open').removeClass('fa-folder');
        }
        e.stopPropagation();

    });
}

function showHideCheckIcon(type, id) {

    if (window['' + type + 'CheckPoints_' + id] == "checked") {
        $("#" + type + "CheckIconBox").show();
    }
    else {
        $("#" + type + "CheckIconBox").hide();
    }

    if (window['' + type + 'CheckRealPoints_' + id] == "checked") {
        $("#" + type + "CheckIconRealPoints").show();
    }
    else {
        $("#" + type + "CheckIconRealPoints").hide();
    }

    if (window['' + type + 'CheckSequence_' + id] == "checked") {
        $("#" + type + "CheckIconSequence").show();
    }
    else {
        $("#" + type + "CheckIconSequence").hide();
    }

}

function openContext(id, name, menuName, event) {

    if (name == "fiber" || name == "tube" || name == "strand" || name == "trench" || name == "duct") {
        showHideCheckIcon(name, id);
    }


    // open the menu with a delay
    const time = menuName.isOpen() ? 100 : 0;

    // hide the current menu (if any)
    menuName.hide();

    // display menu at mouse click position
    setTimeout(() => { menuName.show(event.pageX, event.pageY) }, time);

    // close the menu if the user clicks anywhere on the screen
    document.addEventListener('contextmenu', hideContext, true);
    document.addEventListener('click', hideContext, true);
    HideContextMenuGoolge(MenuMap);
    window["menuName"] = menuName;
    event.preventDefault();
}


function hideContext() {

    // hide the menu
    if (window["menuName"] != "") {
        window["menuName"].hide();
        //hideMenu();
        // remove the listener from the document
        document.removeEventListener('contextmenu', hideContext);
        document.removeEventListener('click', hideContext);
    }
}

