// check if positive numeric value

function isInDesiredForm(str) {
    return /^\+?(0|[1-9]\d*)$/.test(str);
}

function isFloat(n) {
    return Number(n) === n && n % 1 !== 0;
}

function isInt(n) {
    return Number(n) === n && n % 1 === 0;
}

//url for filter
function physicalLayerFilter() {
    var filtredValue;
    var url;
    var checkedOption;
    var urlString = "";

    $("#submitFilter").click(function() {
        $("input[name='filteredField']").each(function() {
            console.log(this.value + " : " + $(this).attr('id'));
            if (this.value) {
                urlString += "&" + $(this).attr('id') + "=" + this.value + "";
            }
        });
        if ($("#currentChecked").prop('checked')) {
            checkedOption = "CurrentPhysicalLayer";
        }
        else {
            checkedOption = "PROJECT";
        }
        urlString += "&getRelatedPointsFilter=" + $("#getRelatedPointsFilter").val() + "";
        urlString += "&updateModfUser=" + updateModfUser;

        window.location.href = getContext() + "/NetworkPhysicalLayer?Checked=" + checkedOption + urlString;
    });
}

function CheckMatching(initialArray, tempArray, IndexInItitialArray) {
    var result = [];
    var alreadyAdded = 0;
    var uniqueChars = tempArray.filter((c, index) => {
        return tempArray.indexOf(c) === index;
    });


    if (uniqueChars.length > 0) {//check results if they includes in projects
        for (let i = 0;i < uniqueChars.length;i++) {
            alreadyAdded = 0;

            for (let j = 0;j < initialArray.length;j++) {
                if (uniqueChars[i] === initialArray[j][IndexInItitialArray]) {

                    if (result.length === 0) {
                        result.push(initialArray[j]);
                    }
                    else {
                        for (let k = 0;k < result.length;k++) {
                            if (result[k] === initialArray[j][IndexInItitialArray]) {
                                alreadyAdded = 1;
                                break;
                            }
                        }
                        if (alreadyAdded === 0) {
                            result.push(initialArray[j]);
                        }
                    }
                }
            }
        }
    }
    else {
        result = [];
    }
    return result;
}

