function creationFromTree(modalId, tableId, auxPtAutocomplete, srcDestAutoComplete) {

    $('#' + modalId).find('input:text').val('');
    $('#' + modalId).find('input:file').val('');
    $('#' + modalId).find('select').val('');
    $('#' + modalId).find('input:checkbox').prop("checked", false);
    $("#" + tableId + " > tbody").empty();

    //Uncheck all checkboxes when opening the popup
    uncheckAutoCompleteCheckboxes(auxPtAutocomplete);
    uncheckAutoCompleteCheckboxes(srcDestAutoComplete);

    $('body').append('<div id="loading"><img id="loading-image" src="' + getContext() + '/resources/images/ajax-loader.gif" alt="Loading..." /><span>Loading, please wait.</span></div>');
    auxDict = [];
    auxDetails = [];

    $("input:checkbox[name='Element']:checked").each(function() {
        var longitude = "";
        var latitude = "";
        ID = $(this).parent().attr('id');
        name = $.trim($(this).parent().children('span').text());
        wareID = "null";

        if ($(this).parent().attr('id').split("_")[0] == "DB") {
            longitude = window["" + $(this).parent().attr('id')][1]
            latitude = window["" + $(this).parent().attr('id')][2]
        }
        else {
            longitude = window["" + $(this).parent().attr('id')][2]
            latitude = window["" + $(this).parent().attr('id')][3]
        }
        auxDetails = [longitude, latitude, "", wareID, ID, name, "", "", 0, 0];
        auxDict.push(auxDetails);
    });

    if (modalId == "fiberPathModal") {
        AuxAppendBOQ(auxDict, "createFromTree", "", TargetFiber, index);
    }
    else if (modalId == "StrandModal") {
        AuxAppendBOQ(auxDict, "createFromTree", "", TargetStrand, index);
    }
    else if (modalId == "trenchModal") {
        AuxAppendBOQ(auxDict, "createFromTree", "", TargetTrench, indextrench);
    }
    else if (modalId == "ductModal") {
        AuxAppendBOQ(auxDict, "createFromTree", "", TargetDuct, indexduct);
    }
    else {
        AuxAppendBOQ(auxDict, "createFromTree", "", TargetTube, index);
    }

    $("#" + modalId).modal('show');
    $("#loading").remove();

}

