function appendingToAuxFromTree(modalId, auxFlag, auxPtAutocomplete, srcDestAutoComplete, selectedID) {

    $("#" + modalId).find('input:file').val('');
    $("#" + modalId).find('input:checkbox').prop("checked", false);

    document.querySelector("#" + auxFlag).value = "opened";

    //Uncheck all autocomplete checkboxes when opening the popup
    uncheckAutoCompleteCheckboxes(auxPtAutocomplete);
    uncheckAutoCompleteCheckboxes(srcDestAutoComplete);

    $('body').append('<div id="loading"><img id="loading-image" src="' + getContext() + '/resources/images/ajax-loader.gif" alt="Loading..." /><span>Loading, please wait.</span></div>')

    if (modalId == "fiberPathModal") {
        url = 'findFiberAuxDetails'
    }
    else if (modalId == "StrandModal") {
        url = 'findStrandDetails'
    }
    else if (modalId == "trenchModal") {
        url = 'findTrenchDetails'
    }
    else if (modalId == "ductModal") {
        url = 'findDuctDetails'
    }
    else {
        url = 'findTubeDetails'
    };

    $.ajax({
        type: "GET",
        url: getContext() + '/' + url,
        data: {
            "ID": selectedID,
        },
        dataType: "json",
        success: function(data) {
            auxDict = data.auxData;
            auxDetails = [];

            $("input:checkbox[name='Element']:checked").each(function() {
                var longitude = "";
                var latitude = "";

                ID = $(this).parent().attr('id');
                name = $.trim($(this).parent().children('span').text());
                wareID = "null";

                if ($(this).parent().attr('id').split("_")[0] == "DB") {
                    longitude = window["" + $(this).parent().attr('id')][1]
                    latitude = window["" + $(this).parent().attr('id')][2]
                }
                else {
                    longitude = window["" + $(this).parent().attr('id')][2]
                    latitude = window["" + $(this).parent().attr('id')][3]
                }

                auxDetails = [longitude, latitude, "", wareID, ID, name, "", "", 0, 0]
                auxDict.push(auxDetails)
            });

            if (modalId == "fiberPathModal") {
                AuxAppendBOQ(auxDict, "createFromTree", "", TargetFiber, index);
            }
            else if (modalId == "StrandModal") {
                AuxAppendBOQ(auxDict, "createFromTree", "", TargetStrand, index);
            }
            else if (modalId == "trenchModal") {
                AuxAppendBOQ(auxDict, "createFromTree", "", TargetTrench, indextrench);
            }
            else if (modalId == "ductModal") {
                AuxAppendBOQ(auxDict, "createFromTree", "", TargetDuct, indexduct);
            }
            else {
                AuxAppendBOQ(auxDict, "createFromTree", "", TargetTube, index);
            }
            data = null;
            auxArray = [];

            $("#" + modalId).modal('show');
            $("#loading").remove();
        }, // end of success
        error: function(result) {
            alert("Error");
        }
    }) // end of ajax	
}



function clearMarkers() {
    console.log(siteCltSrcMarkers);
    for (var key in siteCltSrcMarkers) {
        if (siteCltSrcMarkers.hasOwnProperty(key)) {
            var marker = siteCltSrcMarkers[key];
            marker.setMap(null);
        }
    }
    console.log(placeMarkers);
    for (var key in placeMarkers) {
        if (placeMarkers.hasOwnProperty(key)) {
            var marker = placeMarkers[key];
            marker.setMap(null);
        }
    }
    markerClusterManhole.clearMarkers();
    markerClusterHandhole.clearMarkers();
    markerClusterBackboneDistBoard.clearMarkers();
    markerClusterMetroDistBoard.clearMarkers();
    markerClusterAccessDistBoard.clearMarkers();
    markerClusterSite.clearMarkers();
    $("#manholeCheckAllBoq").prop("checked", false);
    $("#handholeCheckAllBoq").prop("checked", false);
    $("#distBoardCheckAllBoq").prop("checked", false);
    $("#siteCheckAllBoq").prop("checked", false);

    $('.MANHOLE').each(function() {
        var id = $(this).attr('id');
        $("#" + id).children(':checkbox').prop("checked", false);
    });
    $('.HANDHOLE').each(function() {
        var id = $(this).attr('id');
        $("#" + id).children(':checkbox').prop("checked", false);
    });
    $('.DistributionBoard').each(function() {
        var id = $(this).attr('id');
        $("#" + id).children(':checkbox').prop("checked", false);
    });
    $('.SITE').each(function() {
        var id = $(this).attr('id');
        $("#" + id).children(':checkbox').prop("checked", false);
    });

}

function showMarkersCheckedClientSite(CheckboxId, markerId, type) {
    var checkboxCltSite = document.getElementById(CheckboxId);
    checkboxCltSite.addEventListener('change', function() {
        if (type == "site") {
            if (this.checked) {
                if (markersSite[markerId].getMap() == null) {
                    console.log("no marker")
                    markersSite[markerId].setMap(map);
                    markerClusterSite.addMarker(markersSite[markerId]);
                }
            } else {
                markersSite[markerId].setMap(null);
                markerClusterSite.removeMarker(markersSite[markerId]);
            }
        }
        else {
            if (this.checked) {
                siteCltSrcMarkers[markerId].setMap(map);
            } else {
                siteCltSrcMarkers[markerId].setMap(null);
            }
        }
    })
}

